func formatDueDate(d *time.Time) string {
	if d == nil {
		return "—"
	}
	return d.Format("Jan 02, 2006")
}

// editTaskSignals builds the data-on:click expression to populate signals and open the edit modal.
func editTaskSignals(t queries.TaskReadModel) string {
	dueDate := ""
	if t.DueDate != nil {
		dueDate = t.DueDate.Format("2006-01-02")
	}
	return fmt.Sprintf(
		"($_taskModalOpen=true) && ($_taskId='%s') && ($taskTitle='%s') && ($taskDescription='%s') && ($taskPriority='%s') && ($taskDueDate='%s')",
		t.ID, escapeJS(t.Title), escapeJS(t.Description), t.Priority, dueDate,
	)
}

// escapeJS escapes single quotes for inline JS string literals.
func escapeJS(s string) string {
	result := ""
	for _, c := range s {
		if c == '\'' {
			result += "\\'"
		} else {
			result += string(c)
		}
	}
	return result
}

